import{_ as a,c as t,a as r,o as n}from"./app-CEcM0piI.js";const i={};function s(c,e){return n(),t("div",null,e[0]||(e[0]=[r('<p>React最大的一个性能问题就是-React的某个组件的更新会连带着，他的子组件一起更新。</p><h1 id="时间切片" tabindex="-1"><a class="header-anchor" href="#时间切片"><span>时间切片</span></a></h1><p>Vue有依赖收集，做到了最小的更新范围，而React没有做这个事情。所以React要更新，就会有很大的diff算法比对和计算工作。 这大的更新量，虚拟dom比对和计算会花很大时间，这样可能会阻塞住浏览器的工作，导致页面长时间白屏。 React为了解决这个问题选择另一种策略-时间切片，也就是先计算一部分更新，然后让渡给渲染进程渲染，然后再进行下一步更新。以此往复。这样我从使用者的角度，就不会出现长时间白屏了。</p><p>保障在执行更新操作时计算时不能超过16ms，如果超过16ms，京就需要先暂停，让给浏览器进行渲染 ![[Pasted image 20250601182116.png]]</p><h2 id="fiber" tabindex="-1"><a class="header-anchor" href="#fiber"><span>fiber</span></a></h2><p>为了支持这种切片，我们需要把更新化成一个个单元，然后我们也必须有回复上一次计算进度的能力 所以react设计一种数据结构-fiber 每一个组件会被转化为一个fiber结构的对象，组成一个个单元。Fiber让我们有了回复上次中断的计算进度的能力 ![[Pasted image 20250601182308.png]] fiber有很多指针如：父元素、子元素、兄弟元素等，当计算中断后会记录下当前的节点，并在下次恢复后可以知道接下来该计算哪些数据</p><h2 id="优化" tabindex="-1"><a class="header-anchor" href="#优化"><span>优化</span></a></h2><ul><li>对于类组件可以继承PurComponent。对于函数组件应尽量使用React.memo</li><li>避免state修改为同样的值，而产生无意义更新新（PureComponent,函数组件本身就会判断）</li></ul>',8)]))}const p=a(i,[["render",s]]),m=JSON.parse('{"path":"/front/react/4/","title":"4 性能与优化","lang":"zh-CN","frontmatter":{"title":"4 性能与优化","createTime":"2025/06/01 18:28:06","permalink":"/front/react/4/"},"readingTime":{"minutes":1.57,"words":472},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/React/4 性能与优化.md","headers":[]}');export{p as comp,m as data};
